#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/stat.h>
#include <unistd.h>
#include <ftw.h>
#include <errno.h>
#include <limits.h>
#include <ctype.h>
#include <libgen.h>

#define MAX_EXT 6
#define MAX_FTW_DEPTH 20

typedef struct {
    char *src_path;
    char *dst_path;
    char *home_real;
    int is_move;
    char *exclude_exts[MAX_EXT];
    int ext_count;
} context_t;

static context_t ctx;

// Convert string to lowercase for case-insensitive comparison
static void strtolower(char *str) {
    for (; *str; str++) *str = tolower(*str);
}

// Check if file should be excluded based on extension
static int should_exclude(const char *path) {
    if (ctx.ext_count == 0) return 0;

    const char *dot = strrchr(path, '.');
    if (!dot || dot == path) return 0;

    char ext[32];
    strncpy(ext, dot + 1, sizeof(ext) - 1);
    ext[sizeof(ext) - 1] = '\0';
    strtolower(ext);

    for (int i = 0; i < ctx.ext_count; i++) {
        char check_ext[32];
        strncpy(check_ext, ctx.exclude_exts[i], sizeof(check_ext) - 1);
        check_ext[sizeof(check_ext) - 1] = '\0';
        strtolower(check_ext);

        if (strcmp(ext, check_ext) == 0) {
            return 1;
        }
    }
    return 0;
}

// nftw callback function
static int process_entry(const char *fpath, const struct stat *sb,
                         int typeflag, struct FTW *ftwbuf) {
    // Calculate relative path from source
    const char *rel_path = fpath + strlen(ctx.src_path);

    // Build destination path
    char dst_path[PATH_MAX];
    snprintf(dst_path, sizeof(dst_path), "%s%s", ctx.dst_path, rel_path);

    switch (typeflag) {
        case FTW_D:  // Directory (pre-order)
        case FTW_DP: // Directory (post-order)
            if (ftwbuf->level == 0) {
                // Skip root source directory itself
                return 0;
            }

            if (typeflag == FTW_D) { // Pre-order: create directory
                if (mkdir(dst_path, sb->st_mode & 07777) == -1 && errno != EEXIST) {
                    perror("mkdir");
                    return -1;
                }
            } else if (typeflag == FTW_DP && ctx.is_move) { // Post-order: remove if moving
                if (rmdir(fpath) == -1) {
                    perror("rmdir");
                }
            }
            break;

        case FTW_F:  // Regular file
        case FTW_SL: // Symbolic link (treated as regular with FTW_PHYS)
        case FTW_SLN:// Broken symlink
            if (should_exclude(fpath)) {
                return 0; // Skip excluded files
            }

            // Copy file
            FILE *src = fopen(fpath, "rb");
            if (!src) {
                perror("fopen source");
                return 0; // Continue on error
            }

            // Ensure destination directory exists
            char *dst_dir = dirname(strdup(dst_path));
            mkdir(dst_dir, 0755);
            free(dst_dir);

            FILE *dst = fopen(dst_path, "wb");
            if (!dst) {
                perror("fopen destination");
                fclose(src);
                return 0;
            }

            char buffer[4096];
            size_t bytes;
            while ((bytes = fread(buffer, 1, sizeof(buffer), src)) > 0) {
                fwrite(buffer, 1, bytes, dst);
            }

            fclose(src);
            fclose(dst);

            // Preserve permissions
            chmod(dst_path, sb->st_mode & 07777);

            // Remove source if moving
            if (ctx.is_move) {
                if (unlink(fpath) == -1) {
                    perror("unlink");
                }
            }
            break;

        case FTW_DNR: // Directory that couldn't be read
            fprintf(stderr, "Cannot read directory: %s\n", fpath);
            return 0;

        case FTW_NS: // Stat failed
            fprintf(stderr, "Stat failed for: %s\n", fpath);
            return 0;
    }

    return 0;
}

// Remove empty source directory tree after move
static int remove_source_dir(const char *fpath, const struct stat *sb,
                            int typeflag, struct FTW *ftwbuf) {
    if (typeflag == FTW_DP || typeflag == FTW_D) {
        if (ftwbuf->level > 0) { // Don't remove the root itself yet
            if (rmdir(fpath) == -1 && errno != ENOTEMPTY) {
                perror("rmdir");
            }
        }
    }
    return 0;
}

int main(int argc, char *argv[]) {
