        fprintf(stderr, "Usage: %s source_dir destination_dir [-cp|-mv] [ext1 ... ext6]\n", argv[0]);
        fprintf(stderr, "Example: %s ./folder1 ./folder2/folder3 -cp txt pdf\n", argv[0]);
