%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
% CE2: Robust Control of an Electromechanical System
%
%% 2.2 Model-Based H2 Controller Design
% In this part, an H2 state feedback controller is designed for the model
% G3 of the active suspension system. The objective is to design a state
% feedback controller such that the sum of the (squared) two-norm of the
% closed-loop transfer functions from the input disturbance to the output
% and to the input of the system is minimized.
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
clc
clear all
close all
load('data3.mat')
G3 = bj(data3, [5, 5, 5, 5, 1]);
%% Convert the discrete-time model G1 to a continuous-time model (use d2c).
G3_c = d2c(G3);
%% Obtain state-space matrices
[A, B, C, D] = ssdata(G3_c);
n = size(A,1);   % number of states
m = size(B,2);   % number of inputs
p = size(C,1);   % number of outputs

%% Define LMI variables
X = sdpvar(n,n,'symmetric');   % Lyapunov matrix
Y = sdpvar(m,n,'full');        % Y = K*X
Z = sdpvar(m,m,'symmetric');   % auxiliary variable for K*X*K'

%% LMI constraints
% Lyapunov inequality: (A*X - B*Y) + (A*X - B*Y)' + B*B' < 0
Lyap = (A*X - B*Y) + (A*X - B*Y)' + B*B' <= -1e-6*eye(n);  % strict negativity

% X > 0
posX = X >= 1e-6*eye(n);

% Schur complement for Z > Y*X^(-1)*Y'
Schur = [Z, Y; Y', X] >= 1e-6*eye(m+n);

% Combine constraints
Constraints = [Lyap, posX, Schur];

%% Objective: minimize trace(C*X*C') + trace(Z)
Objective = trace(C*X*C') + trace(Z);

%% Solve the LMI
ops = sdpsettings('solver','sedumi','verbose',1);
sol = optimize(Constraints, Objective, ops);

%% Check solution
if sol.problem == 0
    disp('LMI solved successfully.');
    X_opt = value(X);
    Y_opt = value(Y);
    Z_opt = value(Z);
    % Compute controller gain: K = Y * inv(X)
    K = Y_opt / X_opt;
    % Compute H2 norm (upper bound)
    H2_upper = sqrt(value(Objective));
    fprintf('Upper bound on sqrt(sum of squared H2 norms): %g\n', H2_upper);
else
    error('LMI solution failed: %s', sol.info);
end

%% Closed-loop system with state feedback
sys_cl = ss(A - B*K, B, C, zeros(size(D)));
figure;
step(sys_cl);
title('Step Response of H2 State Feedback Closed-Loop System');
grid on;

%% Compare with LQR
R = 1;
Q = eye(n);
[K_lqr, ~, ~] = lqr(A, B, Q, R);
sys_cl_lqr = ss(A - B*K_lqr, B, C, D);
figure;
step(sys_cl_lqr);
title('Step Response of LQR Closed-Loop System');
grid on;

%% Display gains
disp('H2 State Feedback Gain K:');
disp(K);
disp('LQR Gain K_lqr:');
disp(K_lqr);
```

Explanation:
1. The LMI formulation uses the Schur complement to handle the nonlinear term \( K X K^\top \), introducing \( Z \) as an upper bound.
2. The objective \( \text{trace}(C X C^\top) + \text{trace}(Z) \) is minimized, which corresponds to minimizing the sum of squared H2 norms of the transfer functions from disturbance to output and to input.
3. The Lyapunov inequality ensures closed-loop stability and defines the H2 norm condition.
4. The code includes proper strict inequalities via a small tolerance (1e-6).
5. Step responses are plotted for comparison with LQR.

This formulation is convex and can be solved efficiently with YALMIP and solvers like SeDuMi or MOSEK.

