```python
import os
import hashlib
import argparse
from PIL import Image
from pathlib import Path
import sys

def calculate_dhash(image_path, hash_size=8):
    """Calculate perceptual hash using difference hash algorithm"""
    try:
        with Image.open(image_path) as img:
            # Convert to grayscale
            img = img.convert('L')
            # Resize to hash_size x hash_size
            img = img.resize((hash_size + 1, hash_size), Image.LANCZOS)

            # Calculate difference hash
            diff = []
            for row in range(hash_size):
                for col in range(hash_size):
                    pixel_left = img.getpixel((col, row))
                    pixel_right = img.getpixel((col + 1, row))
                    diff.append(pixel_left > pixel_right)

            # Convert to hash
            hash_value = 0
            for i, bit in enumerate(diff):
                if bit:
                    hash_value += 2 ** i
            return hash_value
    except Exception as e:
        print(f"Error calculating dhash for {image_path}: {e}")
        return None

def calculate_file_hash(file_path, algorithm='sha256'):
    """Calculate file hash using specified algorithm"""
    try:
        hash_obj = hashlib.new(algorithm)
        with open(file_path, 'rb') as f:
            for chunk in iter(lambda: f.read(4096), b""):
                hash_obj.update(chunk)
        return hash_obj.hexdigest()
    except Exception as e:
        print(f"Error calculating file hash for {file_path}: {e}")
        return None

def get_image_files(directory):
    """Get all image files in directory recursively"""
    image_extensions = {'.jpg', '.jpeg', '.png', '.bmp', '.tiff', '.webp', '.gif'}
    image_files = []

    for root, _, files in os.walk(directory):
        for file in files:
            file_path = Path(file)
            if file_path.suffix.lower() in image_extensions:
                full_path = os.path.join(root, file)
                image_files.append(full_path)

    return image_files

def hamming_distance(hash1, hash2):
    """Calculate Hamming distance between two hashes"""
    return bin(hash1 ^ hash2).count('1')

def find_exact_duplicates(image_files):
    """Find exact duplicates using file hashes"""
    hash_dict = {}
    duplicates = []

    for image_path in image_files:
        file_hash = calculate_file_hash(image_path)
        if file_hash is None:
            continue

        if file_hash not in hash_dict:
            hash_dict[file_hash] = []
        hash_dict[file_hash].append(image_path)

    for file_hash, paths in hash_dict.items():
        if len(paths) > 1:
            duplicates.append(paths)

    return duplicates

def find_similar_images(image_files, dhash_threshold=10):
    """Find similar images by perceptual hash"""
    hash_dict = {}

    # Calculate perceptual hashes for all images
    for image_path in image_files:
        dhash = calculate_dhash(image_path)
        if dhash is None:
            continue

        if dhash not in hash_dict:
            hash_dict[dhash] = []
        hash_dict[dhash].append(image_path)

    # Group similar images based on hamming distance
    similar_groups = []
    processed_hashes = set()

    for hash_val, paths in hash_dict.items():
        if hash_val in processed_hashes:
            continue

        # Find all similar hashes
        similar_set = {hash_val}
        for other_hash in hash_dict:
            if other_hash != hash_val and other_hash not in processed_hashes:
                if hamming_distance(hash_val, other_hash) <= dhash_threshold:
                    similar_set.add(other_hash)

        # Collect all files from similar groups
        similar_files = []
        for h in similar_set:
            similar_files.extend(hash_dict[h])
            processed_hashes.add(h)

        if len(similar_files) > 1:
            similar_groups.append(similar_files)

    return similar_groups

def delete_files(file_list, keep_first=True, dry_run=False):
    """Delete files from a list, optionally keeping the first one"""
    if not file_list:
        return 0

    deleted_count = 0

    if keep_first:
        files_to_delete = file_list[1:]
        file_to_keep = file_list[0]
        print(f"\nKeeping: {file_to_keep}")
    else:
        files_to_delete = file_list
        file_to_keep = None

    for file_path in files_to_delete:
        try:
            if dry_run:
                print(f"[DRY RUN] Would delete: {file_path}")
            else:
                os.remove(file_path)
                print(f"Deleted: {file_path}")
            deleted_count += 1
        except Exception as e:
            print(f"Error deleting {file_path}: {e}")

    return deleted_count

def main():
    parser = argparse.ArgumentParser(
        description='Find and delete identical or very similar images in directories'
    )
    parser.add_argument('directory', help='Directory to scan for images')
    parser.add_argument('--exact', action='store_true', 
                       help='Find exact duplicates (file hash comparison)')
    parser.add_argument('--similar', action='store_true',
