        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        renderer.shadowMap.type = THREE.PCFSoftShadowMap;
        document.body.appendChild(renderer.domElement);

        // ========== FUNCTION DEFINITION ==========
        // Hyperbolic paraboloid: z = x^2 - y^2
        function f(x, y) {
            return x * x - y * y;
        }

        // ========== GENERATE VERTICES ==========
        const vertices = [];
        const indices = [];
        const colors = [];

        const min = -1.0;
        const max = 1.0;
        const step = 0.1;

        // Generate grid of points
        let index = 0;
        for (let x = min; x <= max; x += step) {
            for (let y = min; y <= max; y += step) {
                const z = f(x, y);
                vertices.push(x, y, z);

                // Color based on height
                const normalizedZ = (z + 2) / 4; // Map from [-2,2] to [0,1]
                colors.push(normalizedZ, 0.5, 1 - normalizedZ);

                index++;
            }
        }

        // Generate indices for triangles
        const xCount = Math.round((max - min) / step) + 1;
        const yCount = Math.round((max - min) / step) + 1;

        for (let i = 0; i < xCount - 1; i++) {
            for (let j = 0; j < yCount - 1; j++) {
                const a = i * yCount + j;
                const b = i * yCount + (j + 1);
                const c = (i + 1) * yCount + j;
                const d = (i + 1) * yCount + (j + 1);

                // Two triangles per quad
                indices.push(a, b, d);
                indices.push(a, d, c);
            }
        }

