        System.out.println();

        // Simulation sizes
        int[] simulations = {36, 500, 10000};

        for (int sim : simulations) {
            System.out.println("Simulation with " + sim + " rolls:");
            System.out.println("X\tCount\tEm Prob\tP(X)");

            int[] counts = new int[11]; // reset counts for each simulation

            // Roll dice sim times
            for (int roll = 0; roll < sim; roll++) {
                int die1 = rand.nextInt(6) + 1;
                int die2 = rand.nextInt(6) + 1;
                int sum = die1 + die2;
                counts[sum - 2]++; // map sum 2->index 0, 12->index 10
