            // Print each row with formatting
            for (int i = 0; i < 11; i++) {
                int sum = i + 2;
                int count = counts[i];
                double empiricalProb = (double) count / sim;
                double theoreticalProb = theoreticalProbs[i];

                // Convert to formatted strings
                String countStr = Integer.toString(count);
                String empStr = df.format(empiricalProb);
                String theoStr = df.format(theoreticalProb);

                // Determine number of tabs for alignment
                // Base: one tab after X, one after Count, one after Em Prob
                // Adjust extra tabs if numbers are short/long
                String tabsAfterCount = "\t";
                if (countStr.length() < 2) {
                    tabsAfterCount += "\t"; // extra tab for single-digit counts
                }
                String tabsAfterEmp = "\t";
                if (empStr.length() < 6) { // typical length 5 or 6
                    tabsAfterEmp += "\t";
                }

                System.out.println(sum + "\t" + count + tabsAfterCount + empStr + tabsAfterEmp + theoStr);
            }
            System.out.println();
        }
    }
}
```

