    PaymentChargesTableAction,
    paymentTableSelectors
} from '@txp-core/payment-transactions-table';
import { cloneDeep, select } from '@txp-core/basic-utils';
import { CreditChargesPaymentTypes } from '@txp-core/payment-transactions-table/dist/paymentTableStateTypes';

export function* outstandingTransactionsHandler(): Generator<Effect, StepResponse, string> {
    const creditTableLines = yield* select(paymentTableSelectors.getCredits);
    const totalOfChargesTable = yield* select(paymentTableSelectors.getTotalOfChargesTable);

    // Create a deep copy to avoid mutating the original state
    const creditTableCopy: CreditChargesPaymentTypes[] = cloneDeep(creditTableLines) || [];

    // Filter only credits that have linked payment amounts (non-empty)
    const creditsWithLinkedPayments = creditTableCopy.filter(
        (credit): credit is CreditChargesPaymentTypes & { linkedPaymentAmount: string } =>
            credit.linkedPaymentAmount !== ''
    );

    let remainingAmount = Number(totalOfChargesTable) || 0;

    // Process credits in priority order (assuming order matters)
    const processedCredits = creditsWithLinkedPayments.map(credit => {
        const amountToApply = Math.min(remainingAmount, credit.openBalance);

        if (amountToApply > 0) {
            credit.linkedPaymentAmount = amountToApply.toString();
            remainingAmount -= amountToApply;
        } else {
            credit.linkedPaymentAmount = '';
        }

        return credit;
