        const processedCredit = processedCreditsMap.get(credit.txnId);
        return processedCredit ? { ...credit, ...processedCredit } : credit;
    });

    yield put(PaymentChargesTableAction.fullCreditsTableUpdate(updatedCreditTable));

    return { result: ResultType.SUCCESS };
}
