Final Answer: In MongoDB, joining multiple nested collections with multiple pipeline conditions involves using the `$lookup` stage with subpipelines, which allows for complex joins with filtering, transformations, and multiple conditions. Here's a comprehensive guide:

## 1. Basic Multi-Collection Join Structure

```javascript
db.orders.aggregate([
  {
    $lookup: {
      from: "customers",
      localField: "customer_id",
      foreignField: "_id",
      as: "customer_info"
    }
  },
  {
    $lookup: {
      from: "products",
      localField: "product_id",
      foreignField: "_id",
      as: "product_details"
    }
  },
  {
    $lookup: {
      from: "shipping",
      localField: "order_id",
      foreignField: "order_ref",
      as: "shipping_info"
    }
  }
])
```

## 2. Using $lookup with Subpipelines (for Complex Conditions)

The subpipeline syntax allows you to apply multiple pipeline stages within the lookup itself:

```javascript
db.orders.aggregate([
  {
    $lookup: {
      from: "products",
      let: { order_product_id: "$product_id", order_quantity: "$quantity" },
      pipeline: [
        {
          $match: {
            $expr: {
              $and: [
                { $eq: ["$_id", "$$order_product_id"] },
                { $gte: ["$stock", "$$order_quantity"] }  // Only join if sufficient stock
              ]
            }
          }
        },
        {
          $project: {
            name: 1,
            price: 1,
            category: 1,
            available_stock: "$stock"
          }
        }
      ],
      as: "available_products"
    }
  }
])
```

## 3. Multiple Nested Collections with Complex Conditions

Here's an example joining three collections with various conditions:

```javascript
db.orders.aggregate([
  // Stage 1: Filter orders first
  {
    $match: {
      status: "completed",
      order_date: { $gte: ISODate("2024-01-01") }
    }
  },

  // Stage 2: Join with customers (with conditions)
  {
    $lookup: {
      from: "customers",
      let: { customerId: "$customer_id" },
      pipeline: [
        {
          $match: {
            $expr: { $eq: ["$_id", "$$customerId"] },
            account_status: "active",
            tier: { $in: ["gold", "platinum"] }
          }
        },
        {
          $project: {
            name: 1,
            email: 1,
            tier: 1,
            join_date: 1
          }
        }
      ],
      as: "customer_details"
    }
  },

  // Stage 3: Unwind customer array (since it's one-to-one)
  {
    $unwind: {
      path: "$customer_details",
      preserveNullAndEmptyArrays: true  // Left outer join behavior
    }
  },

  // Stage 4: Join with order items
  {
    $lookup: {
      from: "order_items",
      let: { orderId: "$_id" },
      pipeline: [
        {
          $match: {
            $expr: { $eq: ["$order_id", "$$orderId"] },
            quantity: { $gt: 0 }
          }
        },
        {
          $lookup: {
            from: "products",
            let: { productId: "$product_id" },
            pipeline: [
              {
                $match: {
                  $expr: { $eq: ["$_id", "$$productId"] },
                  status: "available",
                  price: { $lt: 1000 }
                }
              },
              {
                $project: {
                  product_name: "$name",
                  category: 1,
                  unit_price: "$price"
                }
              }
            ],
            as: "product_info"
          }
        },
        {
          $unwind: "$product_info"
        },
        {
          $addFields: {
            line_total: {
              $multiply: ["$quantity", "$product_info.unit_price"]
            }
          }
        }
      ],
      as: "items"
    }
  },

  // Stage 5: Join with payments
  {
    $lookup: {
      from: "payments",
      let: { orderId: "$_id" },
      pipeline: [
        {
          $match: {
            $expr: { $eq: ["$order_id", "$$orderId"] },
            status: "successful",
            amount: { $gt: 0 }
          }
        },
        {
          $sort: { payment_date: -1 }
        },
        {
          $limit: 1  // Get only the latest successful payment
        }
      ],
      as: "payment_info"
    }
  },

  // Stage 6: Final projection
  {
    $project: {
      order_id: "$_id",
      order_date: 1,
      status: 1,
      customer: "$customer_details",
      items: 1,
      payment: { $arrayElemAt: ["$payment_info", 0] },
      total_items: { $size: "$items" },
      order_total: {
        $sum: "$items.line_total"
      }
    }
  },

  // Stage 7: Final filtering based on joined data
  {
    $match: {
      "customer.tier": "platinum",
      order_total: { $gt: 500 },
      total_items: { $gte: 2 }
    }
  }
])
```

## 4. Key Concepts for Multiple Pipeline Conditions

### A. **$expr for Field Comparisons**
Use `$expr` to compare fields between collections:
```javascript
$expr: { 
  $and: [
    { $eq: ["$local_field", "$$variable_from_let"] },
    { $gt: ["$amount", 100] }
  ]
}
```

### B. **let/pipeline Pattern**
The `let` parameter defines variables that can be used in the subpipeline:
```javascript
let: { var1: "$field1", var2: "$field2" }
```

### C. **Preserving Null Results**
Use `preserveNullAndEmptyArrays: true` with `$unwind` for left outer joins.

### D. **Nested $lookup within $lookup**
You can nest `$lookup` stages inside subpipelines for multi-level joins.

### E. **Performance Considerations**
1. Add indexes on join fields (`customer_id`, `product_id`, etc.)
2. Filter early with `$match` before expensive joins
3. Use `$project` to limit returned fields
4. Consider `$limit` within subpipelines when appropriate

## 5. Common Patterns

### Pattern 1: Conditional Join with Filtering
```javascript
$lookup: {
  from: "collection",
  let: { localField: "$field" },
  pipeline: [
    { $match: { 
      $expr: { $eq: ["$_id", "$$localField"] },
      status: "active",
      created_at: { $gte: ISODate("2024-01-01") }
    }},
    { $project: { _id: 0, name: 1, value: 1 } }
  ],
  as: "joined_data"
}
```

### Pattern 2: Multiple Conditions with Aggregation
```javascript
pipeline: [
  { $match: { $expr: { $eq: ["$foreign_id", "$$local_id"] } } },
  { $match: { category: { $in: ["A", "B"] } } },
  { $group: { _id: "$category", total: { $sum: "$amount" } } }
]
```

This approach allows you to create complex, multi-collection joins with precise control over filtering, transformation, and data flow at each stage of the aggregation pipeline.

