                position += speed * deltaTime;
                if (position > containerWidth) {
                    position = -dot.offsetWidth; // start just left of container
                }
                dot.style.left = position + 'px';

                // Handle pulsing
                const now = Date.now();
                if (isPulsing) {
                    const elapsed = now - pulseStartTime;
                    if (elapsed < pulseDuration) {
                        const progress = elapsed / pulseDuration; // 0 to 1
                        let height;
                        if (progress < 0.5) {
