                        isPulsing = false;
                        dot.style.height = '8px';
                    }
                }

                // Trigger new pulse if it's time
                if (!isPulsing && now >= nextPulseTime) {
                    startPulse();
                }

                requestAnimationFrame(animate);
            }

            // Initialize first pulse
            nextPulseTime = Date.now() + 1500 + Math.random() * 1500;
            requestAnimationFrame(animate);
        })();
    </script>
</body>
</html>
