        }

        if (sz == 3) {
            if (p != -1) cuts.push_back(p);
            return 0;
        }

        return sz;
    };

    int root_sz = dfs(1, -1);

    if (!possible || root_sz != 0) {
        cout << "-1\n";
        return;
    }

    cout << cuts.size() << "\n";
    for (int edge_idx : cuts) {
        cout << edge_idx << " ";
    }
    cout << "\n";
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;
    while (t--) {
        solve();
    }

    return 0;
}
```

**Explanation of the Code:**
1. We store the adjacency list with edge indices.
2. DFS computes subtree sizes and cuts edges when size reaches 3.
3. The `p` parameter in `dfs(v, u)` tracks the edge index from parent to child.
4. When we cut an edge, we store the edge index.
5. If any subtree size exceeds 3, it's impossible.
6. The root must end with size 0 (all vertices partitioned).

**Time Complexity:** O(n) per test case, total O(∑n) ≤ 2×10⁵.

