package com.yourname.bountyplugin;

import net.milkbowl.vault.economy.Economy;
import org.bukkit.ChatColor;
import org.bukkit.entity.Player;
import org.bukkit.event.EventHandler;
import org.bukkit.event.Listener;
import org.bukkit.event.entity.PlayerDeathEvent;

import java.util.Map;

public class PlayerDeathListener implements Listener {
    private final BountyPlugin plugin;

    public PlayerDeathListener(BountyPlugin plugin) {
        this.plugin = plugin;
    }

    @EventHandler
    public void onPlayerDeath(PlayerDeathEvent event) {
        Player victim = event.getEntity();
        Player killer = victim.getKiller();

        // Check if there's a killer and if world is allowed
        if (killer == null || !plugin.getAllowedWorlds().contains(victim.getWorld().getName())) {
            return;
        }

        // Check if victim has a bounty
        Map<String, Double> bounties = plugin.getBounties();
        Double bounty = bounties.remove(victim.getName());

        if (bounty != null && bounty > 0) {
            Economy economy = plugin.getEconomy();
            if (economy != null) {
                // Give bounty to killer
                economy.depositPlayer(killer, bounty);

                // Notify players
                killer.sendMessage(ChatColor.GREEN + "You received $" + String.format("%.2f", bounty) + 
                                 " for killing " + victim.getName() + "!");
                victim.sendMessage(ChatColor.RED + "Your bounty of $" + String.format("%.2f", bounty) + 
                                 " has been claimed by " + killer.getName() + "!");

                // Broadcast to server
                Bukkit.broadcastMessage(ChatColor.GOLD + killer.getName() + " has claimed the $" + 
                                       String.format("%.2f", bounty) + " bounty on " + victim.getName() + "!");

                // Save updated bounties
                plugin.saveBounties();
            }
        }
    }
}
```

