```java
package com.yourname.bountyplugin;

import net.milkbowl.vault.economy.Economy;
import org.bukkit.Bukkit;
import org.bukkit.plugin.RegisteredServiceProvider;
import org.bukkit.plugin.java.JavaPlugin;

import java.util.*;

public class BountyPlugin extends JavaPlugin {
    private Economy economy;
    private Set<String> allowedWorlds;
    private Map<String, Double> bounties;

    @Override
    public void onEnable() {
        // Save default config if it doesn't exist
        saveDefaultConfig();

        // Setup Vault economy
        if (!setupEconomy()) {
            getLogger().severe("Vault economy not found! Disabling plugin...");
            getServer().getPluginManager().disablePlugin(this);
            return;
        }

        // Load configuration
        loadConfig();

        // Register command executor
        getCommand("bounty").setExecutor(new BountyCommand(this));

        // Register event listener
        getServer().getPluginManager().registerEvents(new PlayerDeathListener(this), this);

        getLogger().info("BountyPlugin has been enabled!");
    }

    @Override
    public void onDisable() {
        // Save bounties to config
        saveBounties();
        getLogger().info("BountyPlugin has been disabled!");
    }

    private boolean setupEconomy() {
        if (getServer().getPluginManager().getPlugin("Vault") == null) {
            return false;
        }
        RegisteredServiceProvider<Economy> rsp = getServer().getServicesManager().getRegistration(Economy.class);
        if (rsp == null) {
            return false;
        }
        economy = rsp.getProvider();
        return economy != null;
    }

    private void loadConfig() {
        // Load allowed worlds
        allowedWorlds = new HashSet<>(getConfig().getStringList("allowed-worlds"));

        // Load existing bounties
        bounties = new HashMap<>();
        List<String> bountyList = getConfig().getStringList("bounties");
        for (String entry : bountyList) {
            String[] parts = entry.split(":");
            if (parts.length == 2) {
                try {
                    bounties.put(parts[0], Double.parseDouble(parts[1]));
                } catch (NumberFormatException e) {
                    getLogger().warning("Invalid bounty entry: " + entry);
                }
            }
        }
    }

    public void saveBounties() {
        List<String> bountyList = new ArrayList<>();
        for (Map.Entry<String, Double> entry : bounties.entrySet()) {
            bountyList.add(entry.getKey() + ":" + entry.getValue());
        }
        getConfig().set("bounties", bountyList);
        saveConfig();
    }

    // Getters
    public Economy getEconomy() { return economy; }
    public Set<String> getAllowedWorlds() { return allowedWorlds; }
    public Map<String, Double> getBounties() { return bounties; }
}
```

## **4. BountyCommand.java (Command Executor)**
```java
package com.yourname.bountyplugin;

import net.milkbowl.vault.economy.Economy;
import org.bukkit.Bukkit;
import org.bukkit.ChatColor;
import org.bukkit.command.Command;
import org.bukkit.command.CommandExecutor;
import org.bukkit.command.CommandSender;
import org.bukkit.entity.Player;

public class BountyCommand implements CommandExecutor {
    private final BountyPlugin plugin;

    public BountyCommand(BountyPlugin plugin) {
        this.plugin = plugin;
    }

    @Override
    public boolean onCommand(CommandSender sender, Command command, String label, String[] args) {
        if (args.length == 0) {
            sender.sendMessage(ChatColor.RED + "Usage: /bounty [player] OR /bounty add [player] [amount]");
            return false;
        }

        if (args[0].equalsIgnoreCase("add")) {
            // Handle /bounty add <player> <amount>
            if (!sender.hasPermission("bounty.add")) {
                sender.sendMessage(ChatColor.RED + "You don't have permission to add bounties!");
                return true;
            }

            if (args.length != 3) {
                sender.sendMessage(ChatColor.RED + "Usage: /bounty add [player] [amount]");
                return false;
            }

            if (!(sender instanceof Player)) {
                sender.sendMessage(ChatColor.RED + "Only players can add bounties!");
                return true;
            }

            Player playerSender = (Player) sender;
            String targetName = args[1];
            Player target = Bukkit.getPlayer(targetName);

            if (target == null) {
                sender.sendMessage(ChatColor.RED + "Player '" + targetName + "' is not online or doesn't exist!");
                return true;
            }

            if (target.equals(playerSender)) {
                sender.sendMessage(ChatColor.RED + "You cannot place a bounty on yourself!");
                return true;
            }

            double amount;
            try {
                amount = Double.parseDouble(args[2]);
                if (amount <= 0) {
                    sender.sendMessage(ChatColor.RED + "Amount must be positive!");
                    return true;
                }
            } catch (NumberFormatException e) {
                sender.sendMessage(ChatColor.RED + "Invalid amount! Please enter a valid number.");
                return true;
            }

            Economy economy = plugin.getEconomy();
            if (economy == null) {
                sender.sendMessage(ChatColor.RED + "Economy system not available!");
                return true;
            }

            // Check if player has enough money
            if (economy.getBalance(playerSender) < amount) {
                sender.sendMessage(ChatColor.RED + "You don't have enough money! You need $" + amount);
                return true;
            }

            // Withdraw money from sender
            economy.withdrawPlayer(playerSender, amount);

            // Add to bounty
            Map<String, Double> bounties = plugin.getBounties();
            double currentBounty = bounties.getOrDefault(target.getName(), 0.0);
            double newBounty = currentBounty + amount;
            bounties.put(target.getName(), newBounty);

            // Save to config
            plugin.saveBounties();

            // Notify players
            playerSender.sendMessage(ChatColor.GREEN + "Added $" + amount + " to " + target.getName() + "'s bounty!");
            target.sendMessage(ChatColor.YELLOW + "A bounty of $" + amount + " has been added to your head!");
            Bukkit.broadcastMessage(ChatColor.GOLD + target.getName() + " now has a $" + newBounty + " bounty!");

            return true;
        } else {
            // Handle /bounty <player>
            if (!sender.hasPermission("bounty.view")) {
                sender.sendMessage(ChatColor.RED + "You don't have permission to view bounties!");
                return true;
            }

            String targetName = args[0];
            Map<String, Double> bounties = plugin.getBounties();
            double bounty = bounties.getOrDefault(targetName, 0.0);

            if (bounty > 0) {
                sender.sendMessage(ChatColor.GOLD + "Bounty on " + targetName + ": $" + String.format("%.2f", bounty));
            } else {
                sender.sendMessage(ChatColor.YELLOW + targetName + " has no bounty.");
            }
            return true;
        }
    }
}
```

